/// <reference path="./manga-provider.d.ts" />

class Provider {
    private readonly baseUrl = 'https://mangalivre.to'

    private readonly selectors = {
        search: {
            cards: '.grid .bg-white, .grid article, .grid > div',
            links: "a[href*='/manga/']",
            image: 'img',
        },
        chapters: {
            wrap: '.listing-chapters-wrap, .listing-chapters_wrap',
            rows: '.chapter-box, .wp-manga-chapter',
            links: '.chapter-box a, .wp-manga-chapter a, a[href*="/capitulo-"]',
        },
        pages: {
            images: '.reading-content img.wp-manga-chapter-img, .page-break img.wp-manga-chapter-img, .reading-content img, main img, article img, .prose img',
        },
    }

    private readonly headers = {
        'User-Agent': 'Mozilla/5.0 (Windows NT 10.0; Win64; x64) AppleWebKit/537.36 (KHTML, like Gecko) Chrome/122.0.0.0 Safari/537.36',
        Accept: 'text/html,application/xhtml+xml,application/xml;q=0.9,image/webp,*/*;q=0.8',
    }

    getSettings(): Settings {
        return {
            supportsMultiLanguage: false,
            supportsMultiScanlator: false,
        }
    }

    async search(opts: QueryOptions): Promise<SearchResult[]> {
        const query = String(opts?.query || '').trim()
        if (!query) return []

        try {
            const urls = [
                `${this.baseUrl}/?s=${encodeURIComponent(query)}`,
                `${this.baseUrl}/manga/?s=${encodeURIComponent(query)}`,
                `${this.baseUrl}/pesquisa/?s=${encodeURIComponent(query)}`,
            ]

            const results = new Map<string, SearchResult>()

            for (const url of urls) {
                const response = await this.fetchWithRetry(url)
                if (!response) continue

                const html = await response.text()
                const $ = LoadDoc(html)

                $(this.selectors.search.links).each((_: number, element: any) => {
                    const link = String(element.attr('href') || '').trim()
                    const title = String(element.attr('title') || element.text() || '').trim()
                    if (!link || !title || /\/capitulo-/i.test(link)) return

                    const mangaId = this.extractMangaId(link)
                    if (!mangaId) return

                    const id = mangaId
                    if (results.has(id)) return

                    const card = element.closest(this.selectors.search.cards)
                    const image = this.extractImageUrl(card && card.length() ? card : element)

                    results.set(id, {
                        id,
                        title: this.cleanTitle(title),
                        image,
                    })
                })
            }

            const slug = this.slugify(query)
            const direct = await this.tryDirectSlug(slug, query)
            if (direct && !results.has(direct.id)) {
                results.set(direct.id, direct)
            }

            if (results.size < 3) {
                const catalogResults = await this.searchCatalog(query)
                for (const item of catalogResults) {
                    if (!results.has(item.id)) results.set(item.id, item)
                }
            }

            return Array.from(results.values())
                .sort((a, b) => this.scoreTitleMatch(query, b.title) - this.scoreTitleMatch(query, a.title))
        } catch {
            return []
        }
    }

    async findChapters(mangaId: string): Promise<ChapterDetails[]> {
        console.log('[mangalivreto] findChapters:start', mangaId)
        const normalizedMangaId = this.normalizeMangaId(mangaId)
        console.log('[mangalivreto] findChapters:normalized-id', normalizedMangaId)
        if (!this.isValidMangaId(normalizedMangaId)) {
            console.log('[mangalivreto] findChapters:invalid-id', mangaId)
            return []
        }

        try {
            const url = `${this.baseUrl}/manga/${normalizedMangaId}/`
            console.log('[mangalivreto] findChapters:url', url)
            const response = await this.fetchWithRetry(url)
            if (!response) {
                console.log('[mangalivreto] findChapters:no-response', url)
                return []
            }

            const finalUrl = String((response as any).url || url)
            console.log('[mangalivreto] findChapters:final-url', finalUrl)

            const html = await response.text()
            console.log('[mangalivreto] findChapters:html-length', html.length)
            console.log('[mangalivreto] findChapters:has-listing', /listing-chapters-wrap|listing-chapters_wrap|chapter-box/i.test(html))
            const $ = LoadDoc(html)
            const chapters = new Map<string, ChapterDetails>()

            const chapterScope = $(this.selectors.chapters.wrap)
            console.log('[mangalivreto] findChapters:wrap-count', chapterScope.length())
            const source = chapterScope.length() > 0 ? chapterScope : $
            const links = source.find(this.selectors.chapters.links)
            console.log('[mangalivreto] findChapters:link-count', links.length())

            links.each((_: number, element: any) => {
                const href = String(element.attr('href') || '').trim()
                const rawTitle = String(element.text() || element.attr('title') || '').trim()
                const title = this.cleanTitle(rawTitle)
                if (!href || !title) return
                if (!href.includes(`/manga/${normalizedMangaId}/`)) return

                const chapter = this.extractChapterToken(href, title)
                if (!chapter) return

                chapters.set(href, {
                    id: href,
                    url: href,
                    title,
                    chapter,
                    index: this.chapterSortValue(chapter),
                    language: 'pt-BR',
                })
            })

            console.log('[mangalivreto] findChapters:result-count', chapters.size)
            return Array.from(chapters.values())
                .sort((a, b) => a.index - b.index)
                .map((chapter, index) => ({ ...chapter, index }))
        } catch (error) {
            console.log('[mangalivreto] findChapters:error', String(error))
            return []
        }
    }

    async findChapterPages(chapterId: string): Promise<ChapterPage[]> {
        console.log('[mangalivreto] findChapterPages:start', chapterId)
        if (!this.isValidChapterId(chapterId)) {
            console.log('[mangalivreto] findChapterPages:invalid-id', chapterId)
            return []
        }

        try {
            const response = await this.fetchWithRetry(chapterId)
            if (!response) {
                console.log('[mangalivreto] findChapterPages:no-response', chapterId)
                return []
            }

            const finalUrl = String((response as any).url || chapterId)
            console.log('[mangalivreto] findChapterPages:final-url', finalUrl)
            const html = await response.text()
            console.log('[mangalivreto] findChapterPages:html-length', html.length)
            console.log('[mangalivreto] findChapterPages:has-reading', /reading-content|wp-manga-chapter-img|page-break/i.test(html))

            const $ = LoadDoc(html)
            const pages: ChapterPage[] = []
            const seen = new Set<string>()
            let index = 0

            const images = $(this.selectors.pages.images)
            console.log('[mangalivreto] findChapterPages:image-count', images.length())

            images.each((_: number, element: any) => {
                const src = this.normalizeUrl(String(element.attr('data-src') || element.attr('src') || '').trim())
                if (!src || seen.has(src)) return
                if (!/\.(webp|jpg|jpeg|png|avif)(?:$|\?)/i.test(src)) return
                if (/logo|icon|avatar|banner/i.test(src)) return

                seen.add(src)
                pages.push({
                    url: src,
                    index: index++,
                    headers: {
                        Referer: chapterId,
                        'User-Agent': this.headers['User-Agent'],
                    },
                })
            })

            console.log('[mangalivreto] findChapterPages:result-count', pages.length)
            return pages
        } catch (error) {
            console.log('[mangalivreto] findChapterPages:error', String(error))
            return []
        }
    }

    private async fetchWithRetry(url: string, retries: number = 1): Promise<Response | null> {
        for (let attempt = 0; attempt <= retries; attempt++) {
            try {
                const response = await fetch(url, {
                    headers: this.headers,
                    redirect: 'follow',
                })
                if (response.ok) return response
                if (attempt === retries) return null
            } catch {
                if (attempt === retries) return null
            }
        }
        return null
    }

    private async searchCatalog(query: string): Promise<SearchResult[]> {
        const urls = [
            `${this.baseUrl}/manga/`,
            `${this.baseUrl}/manga/page/2/`,
            `${this.baseUrl}/manga/page/3/`,
        ]

        const results = new Map<string, SearchResult>()
        const normalizedQuery = this.normalizeText(query)

        for (const url of urls) {
            const response = await this.fetchWithRetry(url)
            if (!response) continue

            const html = await response.text()
            const $ = LoadDoc(html)

            $('a[href*="/manga/"]').each((_: number, element: any) => {
                const href = String(element.attr('href') || '').trim()
                const title = this.cleanTitle(String(element.attr('title') || element.text() || '').trim())
                if (!href || !title || /\/capitulo-/i.test(href)) return

                const mangaId = this.extractMangaId(href)
                if (!mangaId) return

                const score = this.scoreTitleMatch(normalizedQuery, title)
                if (score <= 0) return

                const id = mangaId
                if (results.has(id)) return

                results.set(id, {
                    id,
                    title,
                    image: undefined,
                })
            })
        }

        return Array.from(results.values())
    }

    private async tryDirectSlug(slug: string, fallbackTitle: string): Promise<SearchResult | null> {
        if (!slug) return null

        const url = `${this.baseUrl}/manga/${slug}/`
        const response = await this.fetchWithRetry(url)
        if (!response) return null

        const finalUrl = String((response as any).url || url)
        const mangaId = this.extractMangaId(finalUrl)
        if (!mangaId) return null

        const html = await response.text()
        const $ = LoadDoc(html)
        const title = this.cleanTitle(String($('h1').first().text() || $('title').first().text() || fallbackTitle).trim())

        return {
            id: mangaId,
            title,
            image: undefined,
        }
    }

    private extractMangaId(url: string): string | null {
        const match = String(url || '').match(/\/manga\/([^\/]+)\/?/i)
        return match ? match[1] : null
    }

    private extractChapterToken(url: string, title: string): string | null {
        const urlMatch = String(url || '').match(/capitulo-([^\/]+)\/?/i)
        if (urlMatch) return urlMatch[1].replace(/_/g, '.').replace(/,/g, '.')

        const titleMatch = String(title || '').match(/cap(?:[íi]tulo)?\s*([0-9]+(?:[\.,_][0-9]+)?)/i)
        if (titleMatch) return titleMatch[1].replace(/_/g, '.').replace(/,/g, '.')

        return null
    }

    private extractImageUrl(element: any): string | undefined {
        if (!element) return undefined
        const img = element.find ? element.find(this.selectors.search.image).first() : element
        const src = String(img?.attr?.('data-src') || img?.attr?.('src') || '').trim()
        return this.normalizeUrl(src) || undefined
    }

    private normalizeUrl(url: string): string | null {
        const value = String(url || '').trim()
        if (!value) return null
        if (value.startsWith('//')) return `https:${value}`
        if (value.startsWith('/')) return `${this.baseUrl}${value}`
        return value
    }

    private normalizeText(value: string): string {
        return String(value || '')
            .normalize('NFD')
            .replace(/[\u0300-\u036f]/g, '')
            .toLowerCase()
            .replace(/[^a-z0-9]+/g, ' ')
            .replace(/\s+/g, ' ')
            .trim()
    }

    private scoreTitleMatch(query: string, title: string): number {
        const q = this.normalizeText(query)
        const t = this.normalizeText(title)
        if (!q || !t) return 0
        if (q === t) return 100
        if (t.includes(q)) return 80

        const words = q.split(' ').filter(Boolean)
        let score = 0
        for (const word of words) {
            if (t.includes(word)) score += 15
        }
        return score
    }

    private cleanTitle(value: string): string {
        return String(value || '')
            .replace(/\s+/g, ' ')
            .replace(/\s*-\s*Manga Livre.*$/i, '')
            .trim()
    }

    private slugify(value: string): string {
        return String(value || '')
            .normalize('NFD')
            .replace(/[\u0300-\u036f]/g, '')
            .toLowerCase()
            .replace(/[^a-z0-9]+/g, '-')
            .replace(/^-+|-+$/g, '')
    }

    private chapterSortValue(value: string): number {
        const parts = String(value || '').split('.')
        const main = parseFloat(parts[0].replace(',', '.'))
        if (!Number.isFinite(main)) return Number.MAX_SAFE_INTEGER
        if (parts.length === 1) return main
        const decimal = parseFloat(`0.${parts.slice(1).join('')}`)
        return main + (Number.isFinite(decimal) ? decimal : 0)
    }

    private normalizeMangaId(mangaId: string): string {
        const value = String(mangaId || '').trim()
        const prefixed = value.match(/^[a-z0-9_-]+:(.+)$/i)
        return prefixed ? String(prefixed[1] || '').trim() : value
    }

    private isValidMangaId(mangaId: string): boolean {
        return typeof mangaId === 'string' && /^[a-z0-9-]+$/i.test(mangaId)
    }

    private isValidChapterId(chapterId: string): boolean {
        return typeof chapterId === 'string' && chapterId.startsWith('http')
    }
}
